import { MessageEvent } from '@nitrots/nitro-renderer';
import { CommandsListParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/CommandsListParser';

export class CommandsListMessageEvent extends MessageEvent {
    constructor(callback: (event: CommandsListMessageEvent) => void) {
        super(callback, CommandsListParser);
    }

    public getParser(): CommandsListParser {
        return this.parser as CommandsListParser;
    }
}
